        // 100.64.0.0/10 carrier-grade NAT
        if (inRange(ip, "100.64.0.0", 10)) return true;
        // 198.18.0.0/15 benchmarking
        if (inRange(ip, "198.18.0.0", 15)) return true;
        // 192.0.0.0/24 IETF Protocol Assignments
        if (inRange(ip, "192.0.0.0", 24)) return true;
        // Documentation ranges
        if (inRange(ip, "192.0.2.0", 24)) return true;     // TEST-NET-1
        if (inRange(ip, "198.51.100.0", 24)) return true;  // TEST-NET-2
        if (inRange(ip, "203.0.113.0", 24)) return true;   // TEST-NET-3
