        }

        @Override
        public int read() throws IOException {
            ensureAvailable(1);
            int b = super.read();
            if (b >= 0) bytesRead++;
            return b;
        }

        @Override
        public int read(byte[] b, int off, int len) throws IOException {
            Objects.checkFromIndexSize(off, len, b.length);
            if (len == 0) return 0;
            long allowed = maxBytes - bytesRead;
            if (allowed <= 0) {
                throw new IOException("Response exceeded maximum allowed size (" + maxBytes + " bytes)");
            }
            int toRead = (int) Math.min(len, Math.min(Integer.MAX_VALUE, allowed));
            int r = super.read(b, off, toRead);
            if (r > 0) bytesRead += r;
            return r;
        }

        private void ensureAvailable(int need) throws IOException {
            if (bytesRead + need > maxBytes) {
                throw new IOException("Response exceeded maximum allowed size (" + maxBytes + " bytes)");
            }
        }

        public long getBytesRead() {
            return bytesRead;
        }
    }
}

