        if (addr.isAnyLocalAddress() ||
            addr.isLoopbackAddress() ||
            addr.isLinkLocalAddress() ||
            addr.isSiteLocalAddress() ||
            addr.isMulticastAddress()) {
            return false;
        }

        // Broadcast 255.255.255.255
        if (addr.getHostAddress().equals("255.255.255.255")) {
            return false;
        }

        byte[] bytes = addr.getAddress();

        // Block IPv4 special ranges beyond siteLocal/linkLocal
        if (addr instanceof java.net.Inet4Address) {
            if (inIpv4Cidr(bytes, 0, 8)) return false;             // 0.0.0.0/8
            if (inIpv4Cidr(bytes, 100 << 24 | 64 << 16, 10)) return false; // 100.64.0.0/10 (CGNAT)
            if (inIpv4Cidr(bytes, 169 << 24 | 254 << 16, 16)) return false; // 169.254.0.0/16 (link-local, also covered)
            if (inIpv4Cidr(bytes, 198 << 24 | 18 << 16, 15)) return false;  // 198.18.0.0/15 (benchmarking)
        } else if (addr instanceof java.net.Inet6Address) {
            int first = bytes[0] & 0xFF;
            // fc00::/7 Unique local addresses (ULA)
            if ((first & 0xFE) == 0xFC) return false;
            // 2001:db8::/32 documentation? Public but non-routed; allow by default.
        }

        return true;
    }

    private static boolean inIpv4Cidr(byte[] ipv4, int network, int prefixLen) {
        if (ipv4 == null || ipv4.length != 4) return false;
        int ip = ((ipv4[0] & 0xFF) << 24) | ((ipv4[1] & 0xFF) << 16) | ((ipv4[2] & 0xFF) << 8) | (ipv4[3] & 0xFF);
