        try { c.close(); } catch (IOException ignored) {}
    }

    private static void safeDisconnect(HttpURLConnection conn) {
        if (conn != null) {
            try { conn.disconnect(); } catch (Exception ignored) {}
        }
    }

    // InputStream wrapper that enforces a maximum number of bytes read
    private static final class SizeLimitedInputStream extends FilterInputStream {
        private final long max;
        private long count;

        protected SizeLimitedInputStream(InputStream in, long maxBytes) {
            super(in);
            this.max = maxBytes;
        }

        @Override
        public int read() throws IOException {
            int b = super.read();
            if (b != -1) {
                increment(1);
            }
            return b;
        }

        @Override
        public int read(byte[] b, int off, int len) throws IOException {
            int n = super.read(b, off, len);
            if (n > 0) {
                increment(n);
            }
            return n;
        }

        private void increment(long n) throws IOException {
            count += n;
            if (count > max) {
                throw new IOException("Image exceeds maximum allowed size of " + max + " bytes");
            }
        }
    }
}

