        if (in != null) {
            try { in.close(); } catch (IOException ignored) {}
        }
    }

    private static byte[] readUpTo(InputStream in, int maxBytes, boolean[] truncated) throws IOException {
        ByteArrayOutputStream baos = new ByteArrayOutputStream(Math.min(maxBytes, 8192));
        byte[] buf = new byte[8192];
        int total = 0;
        while (true) {
            int toRead = Math.min(buf.length, maxBytes - total);
            if (toRead <= 0) {
                // We've reached the limit; check if there's more data
                int extra = in.read();
                if (extra != -1) {
                    truncated[0] = true;
                }
                break;
            }
            int read = in.read(buf, 0, toRead);
            if (read == -1) {
                break;
            }
            baos.write(buf, 0, read);
            total += read;
        }
        return baos.toByteArray();
    }

    private static boolean isPrivateOrLocalHost(String host) throws UnknownHostException {
        // Fast-path: obvious local names
        String lower = host.toLowerCase(Locale.ROOT);
        if ("localhost".equals(lower) || lower.endsWith(".localhost")) {
