        // If host is an IPv4 literal, validate ranges directly to avoid DNS
        if (IPV4_PATTERN.matcher(host).matches()) {
            String[] parts = host.split("\\.");
            int a = Integer.parseInt(parts[0]);
            int b = Integer.parseInt(parts[1]);
            // 10.0.0.0/8
            if (a == 10) return true;
            // 172.16.0.0/12
            if (a == 172 && (b >= 16 && b <= 31)) return true;
            // 192.168.0.0/16
            if (a == 192 && b == 168) return true;
            // 127.0.0.0/8 loopback
            if (a == 127) return true;
            // 169.254.0.0/16 link-local
            if (a == 169 && b == 254) return true;
            // 0.0.0.0/8, 100.64.0.0/10 (CGNAT), 224.0.0.0/4 multicast, 240.0.0.0/4 reserved
            int secondOctet = b;
            if (a == 0) return true;
            if (a == 100 && (secondOctet >= 64 && secondOctet <= 127)) return true;
            if (a >= 224) return true;
        }

        // Resolve all addresses and ensure none are private/local
        InetAddress[] addresses = InetAddress.getAllByName(host);
        for (InetAddress addr : addresses) {
            if (isPrivateOrLocalAddress(addr)) {
                return true;
            }
        }
        return false;
    }

    private static boolean isPrivateOrLocalAddress(InetAddress addr) {
        if (addr.isAnyLocalAddress()
                || addr.isLoopbackAddress()
                || addr.isLinkLocalAddress()
                || addr.isMulticastAddress()
                || addr.isSiteLocalAddress()) {
            return true;
        }
        // IPv6 Unique Local Addresses (fc00::/7)
        if (addr instanceof Inet6Address) {
            byte[] b = addr.getAddress();
            int first = b[0] & 0xFF;
            if ((first & 0xFE) == 0xFC) {
                return true;
            }
        }
        return false;
    }
}

